const raw = $json;
// BlueDot webhook format
if (raw.transcript || raw.body?.transcript) {
  const t = raw.transcript || raw.body?.transcript || '';
  return [{ json: {
    attendee_name: raw.attendee_name || raw.body?.attendee_name || raw.participants?.[0]?.name || '',
    attendee_email: raw.attendee_email || raw.body?.attendee_email || raw.participants?.[0]?.email || '',
    meeting_title: raw.meeting_title || raw.body?.meeting_title || raw.title || 'Discovery Call',
    meeting_date: raw.meeting_date || raw.body?.meeting_date || raw.created_at || new Date().toISOString(),
    transcript: t.substring(0, 15000),
    bluedot_summary: raw.summary || raw.body?.summary || ''
  }}];
}
// Calendly webhook format
const payload = raw.payload || raw;
const invitee = payload.invitee || {};
const event = payload.event || payload.scheduled_event || {};
return [{ json: {
  attendee_name: invitee.name || raw.name || '',
  attendee_email: invitee.email || raw.email || '',
  meeting_title: event.name || raw.event_type?.name || 'Discovery Call',
  meeting_date: event.start_time || raw.start_time || new Date().toISOString(),
  transcript: raw.transcript || '(Transcript pending - will be available after the meeting)',
  bluedot_summary: ''
}}];

const contact = $('Find Notion Contact').first().json;
const props = contact.properties;
const contactName = props['Name']?.title?.[0]?.text?.content || 'Unknown';
const companyName = props['Company']?.rich_text?.[0]?.text?.content || 'Unknown-Company';
// Slugify for GitHub repo name: lowercase, replace spaces/special chars with hyphens
const repoName = (contactName + '-' + companyName).toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
return [{ json: {
  notion_page_id: contact.id,
  contact_name: contactName,
  company_name: companyName,
  contact_email: props['Email']?.email || '',
  existing_folder_id: props['Drive Folder ID']?.rich_text?.[0]?.text?.content || '',
  folder_name: companyName + '-' + contactName,
  github_repo_name: repoName
}}];

