const raw = $json.content?.[0]?.text || $json.message?.content?.[0]?.text || $json.text || '';

// Parse sections by markers
function getSection(text, marker) {
  const start = text.indexOf(marker);
  if (start === -1) return '';
  const afterMarker = text.substring(start + marker.length);
  const nextMarker = afterMarker.search(/===\w+===/);
  return nextMarker === -1 ? afterMarker.trim() : afterMarker.substring(0, nextMarker).trim();
}

let meetingNotes = getSection(raw, '===MEETING_NOTES===');
let proposal = getSection(raw, '===PROPOSAL===');
let implementationGuide = getSection(raw, '===IMPLEMENTATION_GUIDE===');
let actionItemsRaw = getSection(raw, '===ACTION_ITEMS===');

// Fallback: if section markers not found, try markdown headings
if (!meetingNotes && !proposal) {
  const headingPattern = /^#{1,3}\s+/m;
  if (headingPattern.test(raw)) {
    const sections = raw.split(/^#{1,2}\s+/m).filter(s => s.trim());
    meetingNotes = sections[0] || raw.substring(0, 2000);
    proposal = sections[1] || '';
    implementationGuide = sections[2] || '';
    actionItemsRaw = sections[3] || '';
  } else {
    // No structure found at all - put everything in meeting notes
    meetingNotes = raw.substring(0, 3000);
    proposal = '(Could not parse proposal section - see full response in meeting notes)';
  }
}

// Parse action items JSON
let actionItems = [];
try {
  const jsonMatch = actionItemsRaw.match(/\[[\s\S]*\]/);
  if (jsonMatch) actionItems = JSON.parse(jsonMatch[0]);
} catch(e) { /* AI didn't return valid JSON, fallback to empty */ }

return [{ json: {
  meeting_notes: meetingNotes || '(No meeting notes parsed)',
  proposal: proposal || '(No proposal parsed)',
  implementation_guide: implementationGuide || '(No implementation guide parsed)',
  action_items: actionItems,
  action_items_text: actionItems.length > 0 ? actionItems.map(a => `[${a.priority || 'medium'}] ${a.owner || 'TBD'}: ${a.task || ''}`).join('\n') : '(No action items parsed)',
  full_response: raw
}}];

